/**
 * Memoize a unary function by first argument.
 * @param {(value: unknown) => unknown} fn
 * @returns {(value: unknown) => unknown}
 */
export function memoize(fn) {
  const cache = new Map();

  return (value) => {
    if (cache.has(value)) {
      return cache.get(value);
    }
    const result = fn(value);
    cache.set(value, result);
    return result;
  };
}
